		self._typeNames[self._typeMapCount + 1] = typeName
		self._moduleNames[self._typeMapCount + 1] = moduleName
		self._typeMapCount += 1
	end
end

function SimpleTranspiler.IsTypeReferenced(self: SimpleTranspiler, typeName: string, emittedOutput: string, startOffset: number): boolean
	if typeName == nil then
		return false
	end
	if emittedOutput == nil then
		return false
	end
	local nameLen: number = #typeName
	if nameLen == 0 then
		return false
	end
	local outputLen: number = #emittedOutput
	if outputLen < nameLen then
		return false
	end
	local searchFrom: number = startOffset
	while searchFrom <= outputLen - nameLen do
		local idx: number = SimpleTranspiler.IndexOf(self, emittedOutput, typeName, searchFrom)
		if idx == -1 then
			return false
		end
		local leftOk: boolean = (idx == 0) or not SimpleTranspiler.IsWordChar(self, string.byte(emittedOutput, idx - 1 + 1))
		local afterIdx: number = idx + nameLen
		local rightOk: boolean = (afterIdx >= outputLen) or not SimpleTranspiler.IsWordChar(self, string.byte(emittedOutput, afterIdx + 1))
		if leftOk and rightOk then
			return true
		end
		searchFrom = idx + 1
	end
	return false
end

function SimpleTranspiler.IndexOf(self: SimpleTranspiler, haystack: string, needle: string, startIndex: number): number
