	local needleLen: number = #needle
	local limit: number = haystackLen - needleLen
	for i = startIndex, limit do
		local match: boolean = true
		for j = 0, needleLen - 1 do
			if string.byte(haystack, i + j + 1) ~= string.byte(needle, j + 1) then
				match = false
				break
			end
		end
		if match then
			return i
		end
	end
	return -1
end

function SimpleTranspiler.IsWordChar(self: SimpleTranspiler, c: number): boolean
	if c >= string.byte("a", 1) and c <= string.byte("z", 1) then
		return true
	end
	if c >= string.byte("A", 1) and c <= string.byte("Z", 1) then
		return true
	end
	if c >= string.byte("0", 1) and c <= string.byte("9", 1) then
		return true
	end
	if c == string.byte("_", 1) then
		return true
	end
	return false
end

function SimpleTranspiler.InsertRequires(self: SimpleTranspiler, emittedOutput: string, requireBlock: string): string
